var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이쪽은 조용하고…….","JPN":"こっちは静かだし……","ENG":"Over there’s quiet...","TWN":"這裡很安靜……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이쪽도 조용하고…….","JPN":"こっちもよし……","ENG":"There too...","TWN":"這裡也很安靜……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아무도 없어요. 나오셔도 돼요.","JPN":"誰もいません。出てきてもいいですよ。","ENG":"It’s all clear. You can come out now.","TWN":"沒人，可以出來囉。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으음……. 손님도 오셨는데 집을 비우면 안 돼요…….","JPN":"ううん……お客さんが来てるのに家を空けたらだめですよ……","ENG":"But... We can’t just leave the house. We have a guest.","TWN":"嗯……有客人來，家裡怎麼可以沒有人……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"총소리는 무서워요……. 어서 집에 들어가요…….","JPN":"銃の音は怖いです……早く家に戻りましょう……","ENG":"Gunshots are so frightening... Let’s go home.","TWN":"槍聲好恐怖……我們快回家……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"죄송해요, 아주머니. 지금 집 근처에 무서운 사람들이 나타났어요.","JPN":"すみません、おばさん。今家の近くに怖い人たちが来てるんです。","ENG":"I’m sorry, Madam. There are some very scary people near our house right now.","TWN":"伯母，對不起，現在我們家附近有很多可怕的人，"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"무서워도 조금만 참으세요. 아셨죠?","JPN":"怖くても少し我慢してください。ね？","ENG":"I know it’s scary, but try to bear with it for a little while. Please.","TWN":"所以就算你會怕也要忍耐一下，好嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안젤라 씨, 여기서 보안국 청사로 가려면 어떻게 해야 돼요?","JPN":"アンジェラさん、ここから保安局庁舎までどうやって行くんですか？","ENG":"Angela, how do you get to the National Security office from here?","TWN":"安潔拉，你知道從這裡要怎麼去安全局嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"보안국이면…… 큰길로 나가서 전차를 타는 게 제일 빠를 거야.","JPN":"保安局なら……大通りに出て、電車に乗るのが一番早いと思うわ。","ENG":"National Security... The fastest way would be to get on the main street and take a tram.","TWN":"安全局嗎……出去到大馬路上，攔一台戰車搭便車是最快的。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"좋아요. 머리가 완전히 돌아 버렸어도 보안국 청사까지는 못 올 거예요.","JPN":"よし。完全に頭がいかれても、保安局庁舎までは来れないでしょう。","ENG":"Good. Even if they were completely out of their minds they’d never try for us at the National Security office.","TWN":"很好！他們再怎麼發神經，也不敢跑到安全局來吧！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제가 앞장설게요. 언제 어디서 저 미친놈들이 덮칠지 모르니까.","JPN":"私が先頭に立ちます。いつ、どこであの狂人たちが襲ってくるかわかりませんから。","ENG":"I’ll lead the way. We don’t know when and where those crazy bastards will come from.","TWN":"不知道那些瘋子什麼時候，會從哪裡蹦出來，我來打頭陣吧！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"괜찮니? 손을 무척 떨고 있는데…….","JPN":"大丈夫？　手がすごく震えてるけど……","ENG":"Are you okay? You’re hands are shaking...","TWN":"你還好嗎？你手抖得很厲害欸……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래도 별 수 없잖아요. 밑도 끝도 없이 떠맡긴 했어도 일단은 사람 목숨이 걸린 일인데.","JPN":"でも仕方ないでしょう。やぶから棒に任せられましたけど、一応人の命がかかったことですし。","ENG":"I have no choice but to do. I just took it all of a sudden, but this is a matter of life or death.","TWN":"有什麼辦法！雖然我是臨危受命，但這可是人命關天的事！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저한테 레아 씨처럼 의연함까지 기대하지는 마세요.","JPN":"私にレアさんのような落ち着きぶりまでは期待しないでください。","ENG":"Don’t expect me to be as brave as Leah.","TWN":"不過你們不要期待我會像蕾亞小姐一樣堅強。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"총을 쏴 대는데 냅다 뛰어나가는 쪽이 누가 봐도 겁을 상실한 거죠.","JPN":"弾雨の中でいきなり飛び出すなんて誰が見てもおかしいです。","ENG":"It’s obvious she lost her fear. Who wouldn’t be scared in a place like this?","TWN":"在一片槍林彈雨之中，還能那樣衝出去，很明顯是不怕死的人吧？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"걱정하지 마. 레아는 이런 곳에서 죽지 않아.","JPN":"大丈夫よ。レアはこんなところで死んだりしないわ。","ENG":"Don’t worry. Leah won’t die in a place like this.","TWN":"你放心，蕾亞不會死在這種地方的！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}}]`);export{e as default};